# %% ../../nbs/00_utils/10_subprocess.ipynb #96b0db4f
def tail(s: str | None, limit: int = 40000) -> str:
    """Return the tail of a long string, truncating if it exceeds limit.
    
    Parameters
    ----------
    s : str or None
        String to potentially truncate.
    limit : int
        Maximum length before truncation (default 40000).
    
    Returns
    -------
    str
        Original string if under limit, otherwise truncated with indicator.
    """
    if not s:
        return ""
    return s if len(s) <= limit else f"...[truncated {len(s)-limit} chars]...\n" + s[-limit:]

# %% ../../nbs/00_utils/10_subprocess.ipynb #828fb62c
def ok(errcode: int) -> bool:
    """Return True if the given error code indicates success (zero).
    
    Parameters
    ----------
    errcode : int
        Process return code.
    
    Returns
    -------
    bool
        True if errcode is zero.
    """
    return int(errcode) == 0

# %% ../../nbs/00_utils/10_subprocess.ipynb #7507e279
def which(names: List[str]) -> Optional[str]:
    """Find the first executable in the given list that exists in PATH.
    
    Parameters
    ----------
    names : List[str]
        List of executable names to search for.
    
    Returns
    -------
    str or None
        The first found executable name, or None if none found.
    
    Examples
    --------
    >>> which(['mamba', 'conda', 'pip'])
    'mamba'  # if mamba is installed
    """
    for n in names:
        try:
            subprocess.run([n, "-V"], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            return n
        except Exception:
            continue
    return None

# %% ../../nbs/00_utils/10_subprocess.ipynb #1e06946f
def wrap_with_env(
    cmd: List[str],
    project: Path,
    use_env: bool = True,
    pkg_mgrs: List[str] | None = None,
) -> List[str]:
    """Wrap a command to run inside the project's conda/mamba environment.
    
    If use_env is True and the project has an associated conda/mamba env,
    prefix the command with 'mamba/conda run -n <env_name>'.
    
    Parameters
    ----------
    cmd : List[str]
        Command to wrap.
    project : Path
        Path to the nbdev project root.
    use_env : bool
        If True, attempt to wrap with environment activation.
    pkg_mgrs : List[str] or None
        Package managers to try, in order. Defaults to ['mamba', 'conda', 'micromamba'].
    
    Returns
    -------
    List[str]
        The command, possibly prefixed with environment activation.
    """
    if not use_env:
        return cmd
    
    pkg_mgrs = pkg_mgrs or ["mamba", "conda", "micromamba"]
    exe = which(pkg_mgrs)
    
    env_name = discover_env_name(project)
    if env_name and exe:
        return [exe, "run", "-n", env_name] + cmd
    return cmd  # fallback: run in the current server environment

# %% ../../nbs/00_utils/10_subprocess.ipynb #2b371491
def run(cmd: List[str], cwd: Path) -> Dict[str, Any]:
    """Execute a subprocess command and capture its output.
    
    Parameters
    ----------
    cmd : List[str]
        Command and arguments to execute.
    cwd : Path
        Working directory for the command.
    
    Returns
    -------
    Dict[str, Any]
        Dictionary with keys:
        
        - cmd: The command as a quoted string
        - cwd: Working directory path
        - returncode: Process return code
        - stdout: Standard output (truncated if too long)
        - stderr: Standard error (truncated if too long)
        - ok: True if returncode is zero
    
    Examples
    --------
    >>> result = run(['echo', 'hello'], Path('.'))
    >>> result['ok']
    True
    >>> result['stdout'].strip()
    'hello'
    """
    proc = subprocess.run(cmd, cwd=str(cwd), text=True, capture_output=True)
    return {
        "cmd": " ".join(shlex.quote(x) for x in cmd),
        "cwd": str(cwd),
        "returncode": proc.returncode,
        "stdout": tail(proc.stdout),
        "stderr": tail(proc.stderr),
        "ok": ok(proc.returncode),
    }

# %% ../../nbs/00_utils/10_subprocess.ipynb #e423bb0b
def watch_notebooks(project: Path, interval: float = 2.0, on_change: Optional[str] = None) -> None:
    """Watch notebooks for changes and auto-export.
    
    Parameters
    ----------
    project : Path
        Path to the nbdev project root.
    interval : float, optional
        Polling interval in seconds (default 2.0).
    on_change : str, optional
        Command to run on change (default: nbdev_export).
    
    Notes
    -----
    This is a blocking function that runs until interrupted.
    Uses file modification time polling for simplicity (no external dependencies).
    """
    from nbdev_mcp.utils.paths import nbs_dir, iter_notebooks
    
    nbs = nbs_dir(project)
    log.info(f"Watching notebooks in {nbs} (interval: {interval}s)")
    log.info("Press Ctrl+C to stop watching")
    
    # Build initial mtime cache
    mtimes: Dict[str, float] = {}
    for nb in iter_notebooks(project, use_cache=False):
        try:
            mtimes[str(nb)] = nb.stat().st_mtime
        except OSError:
            pass
    
    log.info(f"Watching {len(mtimes)} notebooks")
    
    # Determine command to run
    cmd = on_change or "nbdev_export"
    
    try:
        while True:
            time.sleep(interval)
            changed = False
            
            # Check for changes
            for nb in iter_notebooks(project, use_cache=False):
                nb_str = str(nb)
                try:
                    current_mtime = nb.stat().st_mtime
                    if nb_str not in mtimes:
                        # New notebook
                        log.info(f"New: {nb.name}")
                        changed = True
                        mtimes[nb_str] = current_mtime
                    elif current_mtime > mtimes[nb_str]:
                        # Modified notebook
                        log.info(f"Changed: {nb.name}")
                        changed = True
                        mtimes[nb_str] = current_mtime
                except OSError:
                    pass
            
            if changed:
                log.info(f"Running: {cmd}")
                try:
                    result = subprocess.run(
                        cmd.split(),
                        cwd=str(project),
                        capture_output=True,
                        text=True
                    )
                    if result.returncode == 0:
                        log.info(f"✓ {cmd} completed successfully")
                    else:
                        log.error(f"✗ {cmd} failed: {result.stderr}")
                except Exception as e:
                    log.error(f"Error running {cmd}: {e}")
                    
    except KeyboardInterrupt:
        log.info("\nWatch mode stopped")
